# scripts/build_package.py — run during CI to create the distributable zip
import zipfile
import os

def build_py_files_archive(source_dir='pipeline', output_path='dist/nordgrid_pipelines.zip'):
    """Package the pipeline modules into a zip for --py-files distribution."""
    os.makedirs('dist', exist_ok=True)

    with zipfile.ZipFile(output_path, 'w', zipfile.ZIP_DEFLATED) as zf:
        for root, dirs, files in os.walk(source_dir):
            for file in files:
                if file.endswith('.py'):
                    filepath = os.path.join(root, file)
                    arcname = os.path.relpath(filepath, '.')  # preserve directory structure
                    zf.write(filepath, arcname)

    print(f"Built {output_path} ({os.path.getsize(output_path):,} bytes)")

if __name__ == '__main__':
    build_py_files_archive()
